const { data: page } = await useAsyncData('page-' + slug.value, async () => {
  const collection = ('content_' + locale.value) as keyof Collections
  const content = await queryCollection(collection).path(slug.value).first()

  // Possibly fallback to default locale if content is missing in non-default locale

  return content
}, {
  watch: [locale],
})

try {
  const [source, modified] = await rpc.enableTimeline(true)
  if (!await Dialog.start(source, modified))
    return
  await rpc.enableTimeline(false)
}
catch {
  devtoolsUiShowNotification({
    message: 'Failed to enable timeline automatically. Check the terminal for more details.',
    icon: 'i-carbon-warning',
    classes: 'text-red',
  })
}

for (const path of paths) {
  if (path.startsWith(base)) {
    resolved.push(path.split('/index.ts')[0]!)
    continue
  }
  const resolvedPath = await resolver.resolvePath(path)
  const dir = parseNodeModulePath(resolvedPath).dir
  if (dir) {
    resolved.push(dir)
    continue
  }
  const index = resolvedPath.lastIndexOf(path)
  resolved.push(index === -1 ? dirname(resolvedPath) : resolvedPath.slice(0, index + path.length))
}

for (const dir of nuxt.options.modulesDir) {
  // we only need to exclude node_modules directories if they are
  // being included automatically by being inside the source directory
  if (!sourceDirs.some(srcDir => dir.startsWith(srcDir))) {
    exclude.add(relativeWithDot(nuxt.options.buildDir, dir))
  }
  nodeExclude.add(relativeWithDot(nuxt.options.buildDir, dir))
  legacyExclude.add(relativeWithDot(nuxt.options.buildDir, dir))
}

for (const resource of Object.values(styles)) {
  // Do not add links to resources that are inlined (vite v5+)
  if (import.meta.dev && 'inline' in getURLQuery(resource.file)) {
    continue
  }
  // Add CSS links in <head> for CSS files
  // - in production
  // - in dev mode when not rendering an island
  link.push({ rel: 'stylesheet', href: renderer.rendererContext.buildAssetsURL(resource.file), crossorigin: '' })
}

if (!NO_SCRIPTS) {
  ssrContext.head.push({
    script: Object.values(scripts).map(resource => (<Script> {
      type: resource.module ? 'module' : null,
      src: renderer.rendererContext.buildAssetsURL(resource.file),
      defer: resource.module ? null : true,
      // if we are rendering script tag payloads that import an async payload
      // we need to ensure this resolves before executing the Nuxt entry
      tagPosition: 'head',
      crossorigin: '',
    })),
  })
}

const middleware: RouteMiddleware = defineNuxtRouteMiddleware((to) => {
  if (import.meta.server || import.meta.test) { return }
  const rules = getRouteRules({ path: to.path })
  if (rules.redirect) {
    const path = rules.redirect.includes('#') ? rules.redirect : (rules.redirect + to.hash)
    if (hasProtocol(path, { acceptRelative: true })) {
      window.location.href = path
      return false
    }
    return path
  }
})

if (!nuxt.options.dev) {
  // DevOnly component tree-shaking - build time only
  addBuildPlugin(DevOnlyPlugin())

  // Extract async data handlers into separate chunks for better performance
  if (nuxt.options.experimental.extractAsyncDataHandlers) {
    addBuildPlugin(ExtractAsyncDataHandlersPlugin({
      sourcemap: !!nuxt.options.sourcemap.client,
      rootDir: nuxt.options.rootDir,
    }), { server: false })
  }
}

if (import.meta.server && nuxtApp.ssrContext) {
  nuxtApp.payload.path = nuxtApp.ssrContext.url

  // Expose nuxt to the renderContext
  nuxtApp.ssrContext.nuxt = nuxtApp
  nuxtApp.ssrContext.payload = nuxtApp.payload

  // Expose client runtime-config to the payload
  nuxtApp.ssrContext.config = {
    public: nuxtApp.ssrContext.runtimeConfig.public,
    app: nuxtApp.ssrContext.runtimeConfig.app,
  }
}

for (const page of pages) {
  if (page.rules) {
    if (Object.keys(page.rules).length) {
      const glob = pathToNitroGlob(prefix + page.path)
      if (glob) {
        paths[glob] = page.rules
      }
    }
    // remove rules to prevent exposing in build
    delete page.rules
  }
  if (page.children?.length) {
    globRouteRulesFromPages(page.children, paths, prefix + page.path + '/')
  }
}

const items = [
  {
    label: 'Account',
    description: 'Make changes to your account here. Click save when you\'re done.',
    icon: 'i-lucide-user',
    slot: 'account' as const
  },
  {
    label: 'Password',
    description: 'Change your password here. After saving, you\'ll be logged out.',
    icon: 'i-lucide-lock',
    slot: 'password' as const
  }
] satisfies TabsItem[]

if (options.colorMode || hasNuxtModule('@nuxtjs/color-mode')) {
  addComponentsDir({
    path: resolve('./runtime/components/color-mode'),
    pathPrefix: false,
    prefix: options.prefix
  })
} else {
  // Stub `useColorMode` composable used in `DashboardSearch` and `ContentSearch` components
  addImportsDir(resolve('./runtime/composables/color-mode'))
}

if (selection.empty) {
  // No selection: continue from cursor position
  const textBefore = getMarkdownBefore(editor, selection.from)
  insertState.value = { pos: selection.from }
  complete(textBefore)
} else {
  // Text selected: append completion after the selection
  const textBefore = getMarkdownBefore(editor, selection.to)
  insertState.value = { pos: selection.to }
  complete(textBefore)
}

for (const locale of routeOptions.locales) {
  // use custom path if found
  const unprefixed = routeOptions.paths?.[locale] ?? route.path

  const prefixed = join('/', locale, unprefixed)
  const usePrefix = options.shouldPrefix(unprefixed, locale, options)

  const data = { route, prefixed, unprefixed, locale, usePrefix, ctx, options }
  for (const localizer of ctx.localizers) {
    if (!localizer.enabled(data)) { continue }
    resultRoutes.push(...localizer.localizer(data))
  }
}

for (const locale of locales) {
  if (!locale.language) {
    console.warn('Locale `language` ISO code is required to generate alternate link')
    continue
  }

  const [language, region] = locale.language.split('-')
  if (language && region && (locale.isCatchallLocale || !localeMap.has(language))) {
    localeMap.set(language, locale)
  }

  localeMap.set(locale.language, locale)
}

if (nuxtRobotsConfig) {
  const { header } = nuxtRobotsConfig
  const robotConfig = getPathRobotConfig(e, { skipSiteIndexable: Boolean(getQuery(e)?.mockProductionEnv) })
  if (header) {
    setHeader(e, 'X-Robots-Tag', robotConfig.rule)
  }
  e.context.robots = robotConfig

  // also compute production config for devtools
  if (import.meta.dev) {
    const productionRobotConfig = getPathRobotConfig(e, { skipSiteIndexable: true })
    setHeader(e, 'X-Robots-Production', productionRobotConfig.rule)
    e.context.robotsProduction = productionRobotConfig
  }
}

Object.entries(standardHeaders).forEach(([headerName, headerValue])  => {
  const optionKey = getKeyFromName(headerName)
  if (optionKey) {
    if (typeof headerValue === 'string') {
      // Normally, standard radix headers should be supplied as string
      const objectValue: any = headerObjectFromString(optionKey, headerValue)
      standardHeadersAsObject[optionKey] = objectValue
    } else {
      // Here we ensure backwards compatibility
      // Because in the pre-rc1 syntax, standard headers could also be supplied in object format
      standardHeadersAsObject[optionKey] = headerValue
      //standardHeaders[headerName] = headerStringFromObject(optionKey, headerValue)
    }
  }
})

try {
  return asCollection(collection) as Collection<T>
}
catch (e) {
  console.warn(
    `[sitemap] Failed to apply sitemap schema to collection. This is likely a Zod version mismatch.`,
    `Pass your Zod instance explicitly: \`defineSitemapSchema({ z })\`. See https://nuxtseo.com/sitemap/guides/content`,
    `Error: ${(e as Error).message}`,
  )
  return collection
}

for (const type in this.options.types) {
  // @ts-expect-error
  (this as unknown as ConsolaInstance)[type as LogType] =
    _mockFn(type as LogType, this.options.types[type as LogType]) ||
    (this as unknown as ConsolaInstance)[type as LogType];
  (this as unknown as ConsolaInstance)[type as LogType].raw = (
    this as unknown as ConsolaInstance
  )[type as LogType];
}

try {
  const currentNodeVersion = JSON.parse(
    await fsp.readFile(join(nitro.options.rootDir, "package.json"), "utf8")
  ).engines.node;
  if (supportedNodeVersions.has(currentNodeVersion)) {
    nodeVersion = currentNodeVersion;
  }
} catch {
  const currentNodeVersion = process.versions.node.slice(0, 2);
  if (supportedNodeVersions.has(currentNodeVersion)) {
    nodeVersion = currentNodeVersion;
  }
}

if (existsSync(headersPath)) {
  const currentHeaders = await readFile(headersPath, "utf8");
  if (/^\/\* /m.test(currentHeaders)) {
    nitro.logger.info(
      "Not adding Nitro fallback to `_headers` (as an existing fallback was found)."
    );
    return;
  }
  nitro.logger.info("Adding Nitro fallback to `_headers` to handle all unmatched routes.");
  contents.unshift(currentHeaders);
}

if (existsSync(redirectsPath)) {
  const currentRedirects = await readFile(redirectsPath, "utf8");
  if (/^\/\* /m.test(currentRedirects)) {
    nitro.logger.info(
      "Not adding Nitro fallback to `_redirects` (as an existing fallback was found)."
    );
    return;
  }
  nitro.logger.info("Adding Nitro fallback to `_redirects` to handle all unmatched routes.");
  contents.unshift(currentRedirects);
}

if (existsSync(redirectsPath)) {
  const currentRedirects = await fsp.readFile(redirectsPath, "utf8");
  if (/^\/\* /m.test(currentRedirects)) {
    nitro.logger.info(
      "Not adding Nitro fallback to `_redirects` (as an existing fallback was found)."
    );
    return;
  }
  nitro.logger.info("Adding Nitro fallback to `_redirects` to handle all unmatched routes.");
  contents = currentRedirects + "\n" + contents;
}

if (existsSync(headersPath)) {
  const currentHeaders = await fsp.readFile(headersPath, "utf8");
  if (/^\/\* /m.test(currentHeaders)) {
    nitro.logger.info(
      "Not adding Nitro fallback to `_headers` (as an existing fallback was found)."
    );
    return;
  }
  nitro.logger.info("Adding Nitro fallback to `_headers` to handle all unmatched routes.");
  contents = currentHeaders + "\n" + contents;
}

if (nitro.options.experimental.tasks) {
  const scannedTasks = await scanTasks(nitro);
  for (const scannedTask of scannedTasks) {
    if (scannedTask.name in nitro.options.tasks) {
      if (!nitro.options.tasks[scannedTask.name].handler) {
        nitro.options.tasks[scannedTask.name].handler = scannedTask.handler;
      }
    } else {
      nitro.options.tasks[scannedTask.name] = {
        handler: scannedTask.handler,
        description: "",
      };
    }
  }
}

if (recreateLockfile) {
  const lockfiles = Array.isArray(resolvedOptions.packageManager.lockFile)
    ? resolvedOptions.packageManager.lockFile
    : [resolvedOptions.packageManager.lockFile];
  for (const lockfile of lockfiles) {
    if (lockfile) fs.rmSync(resolve(resolvedOptions.cwd, lockfile), { force: true });
  }
  return await installDependencies(resolvedOptions);
}
